5. /// <summary>
6. /// Defines formatting options for metric numeral representations.
7. /// </summary>
8. [Flags]
9. public enum MetricFormat
10. {
11.     /// <summary>No special formatting applied.</summary>
12.     None = 0,
13. 
14.     /// <summary>Use the unit symbol instead of the full name (e.g., "k" instead of "kilo").</summary>
15.     UseSymbol = 1,
16. 
17.     /// <summary>Use short scale names (e.g., "billion" vs "milliard").</summary>
18.     UseShortScale = 2,
19. 
20.     /// <summary>Include the base unit name in the output.</summary>
21.     IncludeBaseUnit = 4
22. }
23. 
24. /// <summary>
25. /// Represents a metric unit prefix with its name, symbol, and scale words.
26. /// </summary>
27. internal struct UnitPrefix : IEquatable<UnitPrefix>
28. {
29.     /// <summary>Gets the full name of this prefix (e.g., "kilo", "mega").</summary>
30.     public string Name { get; }
31. 
32.     /// <summary>Gets the short scale word (e.g., "thousand", "million").</summary>
33.     public string ShortScaleWord { get; }
34. 
35.     /// <summary>Gets the long scale word, falling back to short scale if not specified.</summary>
36.     public string LongScaleWord { get; }
37. 
38.     /// <summary>Gets the cached single-character symbol string for this prefix.</summary>
39.     public string SymbolString { get; }
40. 
41.     /// <summary>
42.     /// Initializes a new instance of the <see cref="UnitPrefix"/> struct.
43.     /// </summary>
44.     /// <param name="name">The prefix name.</param>
45.     /// <param name="symbol">The symbol character for this prefix.</param>
46.     /// <param name="shortScaleWord">The short scale word.</param>
47.     /// <param name="longScaleWord">The long scale word, or null to use short scale.</param>
48.     public UnitPrefix(string name, char symbol, string shortScaleWord, string? longScaleWord = null)
49.     {
50.         Name = name;
51.         SymbolString = symbol.ToString();
52.         ShortScaleWord = shortScaleWord;
53.         LongScaleWord = longScaleWord ?? shortScaleWord;
54.     }
55. 
56.     public bool Equals(UnitPrefix other) =>
57.         Name == other.Name && ShortScaleWord == other.ShortScaleWord && LongScaleWord == other.LongScaleWord;
58. 
59.     public override bool Equals(object? obj) => obj is UnitPrefix other && Equals(other);
60. 
61.     public override int GetHashCode() => HashCode.Combine(Name, ShortScaleWord, LongScaleWord);
62. }
63. 
64. /// <summary>
65. /// Provides extension methods for converting numbers to and from metric numeral representations
66. /// (e.g., 1000 → "1k", "2.5M" → 2500000).
67. /// </summary>
68. public static class MetricNumeralExtensions
69. {
70.     private static readonly FrozenDictionary<char, UnitPrefix> UnitPrefixes =
71.         new Dictionary<char, UnitPrefix>
72.         {
73.             ['k'] = new("kilo", 'k', "thousand"),
74.             ['M'] = new("mega", 'M', "million"),
75.             ['G'] = new("giga", 'G', "billion", "milliard"),
76.             ['T'] = new("tera", 'T', "trillion", "billion"),
77.             ['P'] = new("peta", 'P', "quadrillion", "billiard"),
78.             ['E'] = new("exa", 'E', "quintillion", "trillion"),
79.             ['Z'] = new("zetta", 'Z', "sextillion", "trilliard"),
80.             ['Y'] = new("yotta", 'Y', "septillion", "quadrillion"),
81.             ['m'] = new("milli", 'm', "thousandth"),
82.             ['μ'] = new("micro", 'μ', "millionth"),
83.             ['n'] = new("nano", 'n', "billionth", "milliardth"),
84.             ['p'] = new("pico", 'p', "trillionth", "billionth"),
85.             ['f'] = new("femto", 'f', "quadrillionth", "billiardth"),
86.             ['a'] = new("atto", 'a', "quintillionth", "trillionth"),
87.             ['z'] = new("zepto", 'z', "sextillionth", "trilliardth"),
88.             ['y'] = new("yocto", 'y', "septillionth", "quadrillionth"),
89.         }.ToFrozenDictionary();
90. 
91.     // Precomputed exponent→symbol lookup eliminates the O(n) scan in GetSymbolForExponent
92.     private static readonly FrozenDictionary<int, char> ExponentToSymbol =
93.         new Dictionary<int, char>
94.         {
95.             [3] = 'k', [6] = 'M', [9] = 'G', [12] = 'T', [15] = 'P', [18] = 'E', [21] = 'Z', [24] = 'Y',
96.             [-3] = 'm', [-6] = 'μ', [-9] = 'n', [-12] = 'p', [-15] = 'f', [-18] = 'a', [-21] = 'z', [-24] = 'y',
97.         }.ToFrozenDictionary();
98. 
99.     // Precomputed name→symbol lookup for O(1) name-based parsing instead of 16× string.Replace
100.     private static readonly FrozenDictionary<string, char> NameToSymbol =
101.         UnitPrefixes.ToFrozenDictionary(kvp => kvp.Value.Name, kvp => kvp.Key);
102. 
103.     // Cached powers of 10 to avoid recomputing Math.Pow on every call
104.     private static readonly FrozenDictionary<int, double> PowersOf10 =
105.         ExponentToSymbol.Keys.ToFrozenDictionary(e => e, e => Math.Pow(10, e));
106. 
107.     /// <summary>
108.     /// Converts a number to its metric representation using the specified formatting options.
109.     /// </summary>
110.     /// <param name="input">The number to convert.</param>
111.     /// <param name="formats">Formatting options controlling symbol vs name and scale.</param>
112.     /// <param name="decimals">Optional number of decimal places to round to.</param>
113.     /// <returns>A string with the metric representation (e.g., "1.5k" or "1.5 kilo").</returns>
114.     /// <example>
115.     /// <code>
116.     /// 1500.ToMetric() => "1.5k"
117.     /// 1500.ToMetric(MetricFormat.None) => "1.5 kilo"
118.     /// 2500000.ToMetric(MetricFormat.UseSymbol) => "2.5M"
119.     /// </code>
120.     /// </example>
121.     public static string ToMetric(this double input, MetricFormat formats = MetricFormat.UseSymbol, int? decimals = null)
122.     {
123.         if (double.IsNaN(input) || double.IsInfinity(input))
124.         {
125.             return input.ToString();
126.         }
127. 
128.         if (Math.Abs(input) < 1e-24)
129.         {
130.             return "0";
131.         }
132. 
133.         var isNegative = input < 0;
134.         input = Math.Abs(input);
135. 
136.         var exponent = (int)Math.Floor(Math.Log10(input));
137.         var metricExponent = exponent - (exponent % 3);
138. 
139.         if (metricExponent == 0)
140.         {
141.             var formatted = decimals.HasValue ? input.ToString($"F{decimals}") : input.ToString("G");
142.             return isNegative ? $"-{formatted}" : formatted;
143.         }
144. 
145.         var symbol = ExponentToSymbol.GetValueOrDefault(metricExponent);
146.         if (symbol == default)
147.         {
148.             var fallback = input.ToString("G");
149.             return isNegative ? $"-{fallback}" : fallback;
150.         }
151. 
152.         var scaledValue = input / PowersOf10[metricExponent];
153.         var valueStr = decimals.HasValue ? scaledValue.ToString($"F{decimals}") : scaledValue.ToString("G4");
154. 
155.         var suffix = formats.HasFlag(MetricFormat.UseSymbol)
156.             ? UnitPrefixes[symbol].SymbolString
157.             : $" {GetPrefixName(symbol, formats)}";
158. 
159.         return isNegative ? $"-{valueStr}{suffix}" : $"{valueStr}{suffix}";
160.     }
161. 
162.     /// <summary>
163.     /// Converts a metric string representation back to a number.
164.     /// </summary>
165.     /// <param name="input">The metric string to parse (e.g., "1.5k", "2.5 mega").</param>
166.     /// <returns>The numeric value represented by the metric string.</returns>
167.     /// <exception cref="ArgumentException">Thrown when the input is not a valid metric representation.</exception>
168.     /// <example>
169.     /// <code>
170.     /// "1.5k".FromMetric() => 1500
171.     /// "2.5M".FromMetric() => 2500000
172.     /// "100m".FromMetric() => 0.1
173.     /// </code>
174.     /// </example>
175.     public static double FromMetric(this string input)
176.     {
177.         ArgumentException.ThrowIfNullOrWhiteSpace(input);
178. 
179.         input = input.Trim();
180.         if (double.TryParse(input, out var directParse))
181.         {
182.             return directParse;
183.         }
184. 
185.         // Try symbol-based parsing first
186.         var lastChar = input[^1];
187.         if (UnitPrefixes.TryGetValue(lastChar, out var prefix))
188.         {
189.             var numericPart = input[..^1].Trim();
190.             if (double.TryParse(numericPart, out var value))
191.             {
192.                 var exponent = GetExponentForSymbol(lastChar);
193.                 return value * PowersOf10[exponent];
194.             }
195.         }
196. 
197.         // Try name-based parsing
198.         var nameInput = ReplaceNameBySymbol(input);
199.         if (nameInput != input)
200.         {
201.             return nameInput.FromMetric();
202.         }
203. 
204.         throw new ArgumentException($"Invalid metric numeral: '{input}'", nameof(input));
205.     }
206. 
207.     /// <summary>
208.     /// Determines whether the given string is a valid metric numeral.
209.     /// </summary>
210.     /// <param name="input">The string to validate.</param>
211.     /// <returns>true if the string can be parsed as a metric numeral; otherwise, false.</returns>
212.     public static bool IsValidMetricNumeral(this string input)
213.     {
214.         if (string.IsNullOrWhiteSpace(input))
215.         {
216.             return false;
217.         }
218. 
219.         input = input.Trim();
220.         if (double.TryParse(input, out _))
221.         {
222.             return true;
223.         }
224. 
225.         var index = input.Length - 1;
226.         var last = input[index];
227.         var isSymbol = UnitPrefixes.ContainsKey(last);
228.         return isSymbol && double.TryParse(input[..index], out _);
229.     }
230. 
231.     /// <summary>
232.     /// Replaces a metric prefix name with its corresponding symbol in the input string.
233.     /// Uses O(1) dictionary lookup instead of iterating all prefixes.
234.     /// </summary>
235.     /// <param name="input">The string containing a metric prefix name.</param>
236.     /// <returns>The string with the prefix name replaced by its symbol, or the original string if none found.</returns>
237.     private static string ReplaceNameBySymbol(string input)
238.     {
239.         foreach (var kvp in NameToSymbol)
240.         {
241.             var idx = input.IndexOf(kvp.Key, StringComparison.Ordinal);
242.             if (idx >= 0)
243.             {
244.                 return string.Concat(input.AsSpan(0, idx), UnitPrefixes[kvp.Value].SymbolString, input.AsSpan(idx + kvp.Key.Length));
245.             }
246.         }
247. 
248.         return input;
249.     }
250. 
251.     private static char? GetSymbolForExponent(int exponent) =>
252.         ExponentToSymbol.TryGetValue(exponent, out var symbol) ? symbol : null;
253. 
254.     private static int GetExponentForSymbol(char symbol) =>
255.         symbol switch
256.         {
257.             'k' => 3, 'M' => 6, 'G' => 9, 'T' => 12, 'P' => 15, 'E' => 18, 'Z' => 21, 'Y' => 24,
258.             'm' => -3, 'μ' => -6, 'n' => -9, 'p' => -12, 'f' => -15, 'a' => -18, 'z' => -21, 'y' => -24,
259.             _ => 0
260.         };
261. 
262.     private static string GetPrefixName(char symbol, MetricFormat formats)
263.     {
264.         if (!UnitPrefixes.TryGetValue(symbol, out var prefix))
265.         {
266.             return symbol.ToString();
267.         }
268. 
269.         return formats.HasFlag(MetricFormat.UseShortScale) ? prefix.ShortScaleWord : prefix.LongScaleWord;
270.     }
271. }
