             ['M'] = new("mega", 'M', "million"),
             ['G'] = new("giga", 'G', "billion", "milliard"),
             ['T'] = new("tera", 'T', "trillion", "billion"),
             ['P'] = new("peta", 'P', "quadrillion", "billiard"),
             ['E'] = new("exa", 'E', "quintillion", "trillion"),
             ['Z'] = new("zetta", 'Z', "sextillion", "trilliard"),
             ['Y'] = new("yotta", 'Y', "septillion", "quadrillion"),
             ['m'] = new("milli", 'm', "thousandth"),
             ['μ'] = new("micro", 'μ', "millionth"),
             ['n'] = new("nano", 'n', "billionth", "milliardth"),
             ['p'] = new("pico", 'p', "trillionth", "billionth"),
             ['f'] = new("femto", 'f', "quadrillionth", "billiardth"),
             ['a'] = new("atto", 'a', "quintillionth", "trillionth"),
